const KATAKANA_NAME_RE = /^[ァ-ヺー・]+$/;
const TEAM_ID_TO_NAME = {
  0: '東京ヤクルトスワローズ',
  1: '阪神タイガース',
  2: '横浜DeNAベイスターズ',
  3: '広島東洋カープ',
  4: '読売ジャイアンツ',
  5: '中日ドラゴンズ',
  6: '福岡ソフトバンクホークス',
  7: '北海道日本ハムファイターズ',
  8: '千葉ロッテマリーンズ',
  9: '東北楽天ゴールデンイーグルス',
  10: 'オリックス・バファローズ',
  11: '埼玉西武ライオンズ',
};

function isKatakanaName(name = '') {
  const normalized = String(name).replace(/[ 　]/g, '');
  return KATAKANA_NAME_RE.test(normalized);
}

for (const [teamId, team] of Object.entries(NPB2025_ROSTERS)) {
  const teamName = TEAM_ID_TO_NAME[Number(teamId)] ?? '';
  for (const player of [...team.batters, ...team.pitchers]) {
    if (player.isForeign == null && isKatakanaName(player.name)) {
      player.isForeign = true;
    }
    const key = `${teamName}::${player.name}`;
    const contractEndYear = MULTI_YEAR_CONTRACT_END_YEAR_BY_PLAYER.get(key);
    player.contractEndYear = Number.isInteger(contractEndYear) ? contractEndYear : DEFAULT_CONTRACT_END_YEAR;
  }
}
